295→#[tauri::command]
296→fn get_branch_diff(
297→    repo_path: String,
298→    branch: String,
299→) -> Result<Vec<FileDiff>, String> {
300→    let repo = git::open_repo(&repo_path)?;
301→
302→    // Resolve the branch HEAD
303→    let branch_ref = repo
304→        .find_branch(&branch, git2::BranchType::Local)
305→        .map_err(|e| format!("Branch not found: {}", e))?;
306→    let branch_commit = branch_ref
307→        .get()
308→        .peel_to_commit()
309→        .map_err(|e| format!("Failed to resolve branch HEAD: {}", e))?;
310→
311→    // Find the default branch (try main, then master)
312→    let default_branch_name = if repo.find_branch("main", git2::BranchType::Local).is_ok() {
313→        "main"
314→    } else if repo.find_branch("master", git2::BranchType::Local).is_ok() {
315→        "master"
316→    } else {
317→        return Err("No default branch (main/master) found".to_string());
318→    };
319→
320→    // If we're diffing the default branch against itself, return empty
321→    if branch == default_branch_name {
322→        return Ok(Vec::new());
323→    }
324→
325→    let default_ref = repo
326→        .find_branch(default_branch_name, git2::BranchType::Local)
327→        .map_err(|e| format!("Default branch error: {}", e))?;
328→    let default_commit = default_ref
329→        .get()
330→        .peel_to_commit()
331→        .map_err(|e| format!("Failed to resolve default branch: {}", e))?;
332→
333→    // Find merge base
334→    let merge_base_oid = repo
335→        .merge_base(default_commit.id(), branch_commit.id())
336→        .map_err(|e| format!("Failed to find merge base: {}", e))?;
337→    let merge_base_commit = repo
338→        .find_commit(merge_base_oid)
339→        .map_err(|e| format!("Failed to find merge base commit: {}", e))?;
340→
341→    let base_tree = merge_base_commit
342→        .tree()
343→        .map_err(|e| format!("Failed to get base tree: {}", e))?;
344→    let branch_tree = branch_commit
345→        .tree()
346→        .map_err(|e| format!("Failed to get branch tree: {}", e))?;
347→
348→    let diff = repo
349→        .diff_tree_to_tree(Some(&base_tree), Some(&branch_tree), None)
350→        .map_err(|e| format!("Failed to compute branch diff: {}", e))?;
351→
352→    collect_diff_files(&diff)
353→}
