 19→#[tauri::command]
 20→fn list_repos() -> Result<Vec<git::RepoInfo>, String> {
 21→    let repo_paths = config::discover_repos();
 22→    let mut repos = Vec::new();
 23→    for path in repo_paths {
 24→        match git::get_repo_info(&path) {
 25→            Ok(info) => repos.push(info),
 26→            Err(e) => eprintln!("Skipping repo {}: {}", path, e),
 27→        }
 28→    }
 29→    Ok(repos)
 30→}
