238→#[derive(serde::Serialize)]
239→struct FileDiff {
240→    path: String,
241→    status: String, // "added", "modified", "deleted"
242→    hunks: Vec<DiffHunk>,
243→}
244→
245→#[derive(serde::Serialize)]
246→struct DiffHunk {
247→    header: String,
248→    lines: Vec<DiffLine>,
249→}
250→
251→#[derive(serde::Serialize)]
252→struct DiffLine {
253→    kind: String, // "add", "delete", "context"
254→    content: String,
255→    old_lineno: Option<u32>,
256→    new_lineno: Option<u32>,
257→}
258→
259→/// Convert a git2::Diff into our FileDiff structs
260→fn collect_diff_files(diff: &git2::Diff) -> Result<Vec<FileDiff>, String> {
261→    let mut files: Vec<FileDiff> = Vec::new();
262→
263→    diff.print(git2::DiffFormat::Patch, |delta, hunk, line| {
264→        let path = delta
265→            .new_file()
266→            .path()
267→            .or_else(|| delta.old_file().path())
268→            .map(|p| p.to_string_lossy().to_string())
269→            .unwrap_or_default();
270→
271→        let status = match delta.status() {
272→            git2::Delta::Added => "added",
273→            git2::Delta::Deleted => "deleted",
274→            _ => "modified",
275→        };
276→
277→        // Ensure we have a FileDiff entry for this path
278→        if files.last().map_or(true, |f| f.path != path) {
279→            files.push(FileDiff {
280→                path: path.clone(),
281→                status: status.to_string(),
282→                hunks: Vec::new(),
283→            });
284→        }
285→
286→        let file = files.last_mut().unwrap();
287→
288→        // New hunk
289→        if let Some(h) = hunk {
290→            let header = std::str::from_utf8(h.header()).unwrap_or("").to_string();
291→            if file.hunks.last().map_or(true, |last| last.header != header) {
292→                file.hunks.push(DiffHunk {
293→                    header,
294→                    lines: Vec::new(),
295→                });
296→            }
297→        }
298→
299→        // Diff line
300→        if let Some(current_hunk) = file.hunks.last_mut() {
301→            let kind = match line.origin() {
302→                '+' => "add",
303→                '-' => "delete",
304→                ' ' => "context",
305→                _ => return true,
306→            };
307→            let content = std::str::from_utf8(line.content()).unwrap_or("").to_string();
308→            current_hunk.lines.push(DiffLine {
309→                kind: kind.to_string(),
310→                content,
311→                old_lineno: line.old_lineno(),
312→                new_lineno: line.new_lineno(),
313→            });
314→        }
315→
316→        true
317→    })
318→    .map_err(|e| format!("Failed to print diff: {}", e))?;
319→
320→    Ok(files)
321→}
322→
323→#[tauri::command]
324→fn get_checkpoint_diff(
325→    repo_path: String,
326→    commit_sha: String,
327→) -> Result<Vec<FileDiff>, String> {
328→    if commit_sha.is_empty() {
329→        return Err("No commit SHA available for this checkpoint".to_string());
330→    }
331→
332→    let repo = git::open_repo(&repo_path)?;
333→    let oid = git2::Oid::from_str(&commit_sha)
334→        .map_err(|e| format!("Invalid commit SHA: {}", e))?;
335→    let commit = repo
336→        .find_commit(oid)
337→        .map_err(|e| format!("Commit not found: {}", e))?;
338→
339→    let tree = commit
340→        .tree()
341→        .map_err(|e| format!("Failed to get tree: {}", e))?;
342→
343→    // Diff against parent (or empty tree if no parent)
344→    let parent_tree = commit
345→        .parent(0)
346→        .ok()
347→        .and_then(|p| p.tree().ok());
348→
349→    let diff = repo
350→        .diff_tree_to_tree(parent_tree.as_ref(), Some(&tree), None)
351→        .map_err(|e| format!("Failed to compute diff: {}", e))?;
352→
353→    collect_diff_files(&diff)
354→}
