356→#[tauri::command]
357→fn get_branch_diff(
358→    repo_path: String,
359→    branch: String,
360→) -> Result<Vec<FileDiff>, String> {
361→    let repo = git::open_repo(&repo_path)?;
362→
363→    // Resolve the branch HEAD
364→    let branch_ref = repo
365→        .find_branch(&branch, git2::BranchType::Local)
366→        .map_err(|e| format!("Branch not found: {}", e))?;
367→    let branch_commit = branch_ref
368→        .get()
369→        .peel_to_commit()
370→        .map_err(|e| format!("Failed to resolve branch HEAD: {}", e))?;
371→
372→    // Find the default branch (try main, then master)
373→    let default_branch_name = if repo.find_branch("main", git2::BranchType::Local).is_ok() {
374→        "main"
375→    } else if repo.find_branch("master", git2::BranchType::Local).is_ok() {
376→        "master"
377→    } else {
378→        return Err("No default branch (main/master) found".to_string());
379→    };
380→
381→    // If we're diffing the default branch against itself, return empty
382→    if branch == default_branch_name {
383→        return Ok(Vec::new());
384→    }
385→
386→    let default_ref = repo
387→        .find_branch(default_branch_name, git2::BranchType::Local)
388→        .map_err(|e| format!("Default branch error: {}", e))?;
389→    let default_commit = default_ref
390→        .get()
391→        .peel_to_commit()
392→        .map_err(|e| format!("Failed to resolve default branch: {}", e))?;
393→
394→    // Find merge base
395→    let merge_base_oid = repo
396→        .merge_base(default_commit.id(), branch_commit.id())
397→        .map_err(|e| format!("Failed to find merge base: {}", e))?;
398→    let merge_base_commit = repo
399→        .find_commit(merge_base_oid)
400→        .map_err(|e| format!("Failed to find merge base commit: {}", e))?;
401→
402→    let base_tree = merge_base_commit
403→        .tree()
404→        .map_err(|e| format!("Failed to get base tree: {}", e))?;
405→    let branch_tree = branch_commit
406→        .tree()
407→        .map_err(|e| format!("Failed to get branch tree: {}", e))?;
408→
409→    let diff = repo
410→        .diff_tree_to_tree(Some(&base_tree), Some(&branch_tree), None)
411→        .map_err(|e| format!("Failed to compute branch diff: {}", e))?;
412→
413→    collect_diff_files(&diff)
414→}
