416→#[tauri::command]
417→fn watch_repo(
418→    repo_path: String,
419→    app: tauri::AppHandle,
420→    state: State<'_, Mutex<AppState>>,
421→) -> Result<(), String> {
422→    let mut app_state = state.lock().map_err(|_| "State lock error".to_string())?;
423→
424→    // Don't double-watch
425→    if app_state.watched_repos.contains(&repo_path) {
426→        return Ok(());
427→    }
428→    app_state.watched_repos.insert(repo_path.clone());
429→
430→    let app_handle = app.clone();
431→    let repo_path_for_closure = repo_path.clone();
432→    watcher::watch_repo(&repo_path, move |event| {
433→        let event_name = match event {
434→            watcher::WatchEvent::CheckpointChanged => "checkpoint-changed",
435→            watcher::WatchEvent::SessionChanged(_) => "session-changed",
436→            watcher::WatchEvent::ConfigChanged => "config-changed",
437→        };
438→        let _ = app_handle.emit(event_name, serde_json::json!({
439→            "repoPath": repo_path_for_closure,
440→        }));
441→    })?;
442→
443→    Ok(())
444→}
