446→#[cfg_attr(mobile, tauri::mobile_entry_point)]
447→pub fn run() {
448→    tauri::Builder::default()
449→        .plugin(tauri_plugin_opener::init())
450→        .plugin(tauri_plugin_window_state::Builder::default().build())
451→        .manage(Mutex::new(AppState {
452→            pty_manager: pty::PtyManager::new(),
453→            watched_repos: HashSet::new(),
454→        }))
455→        .setup(|app| {
456→            // System tray
457→            use tauri::menu::{MenuBuilder, MenuItemBuilder};
458→            use tauri::tray::TrayIconBuilder;
459→            use tauri::Manager;
460→
461→            let show = MenuItemBuilder::with_id("show", "Show Entire").build(app)?;
462→            let quit = MenuItemBuilder::with_id("quit", "Quit").build(app)?;
463→            let menu = MenuBuilder::new(app)
464→                .item(&show)
465→                .separator()
466→                .item(&quit)
467→                .build()?;
468→
469→            let _tray = TrayIconBuilder::new()
470→                .tooltip("Entire Desktop")
471→                .menu(&menu)
472→                .on_menu_event(move |app, event| {
473→                    match event.id().as_ref() {
474→                        "show" => {
475→                            if let Some(window) = app.get_webview_window("main") {
476→                                let _ = window.show();
477→                                let _ = window.set_focus();
478→                            }
479→                        }
480→                        "quit" => {
481→                            app.exit(0);
482→                        }
483→                        _ => {}
484→                    }
485→                })
486→                .on_tray_icon_event(|tray, event| {
487→                    if let tauri::tray::TrayIconEvent::Click { .. } = event {
488→                        let app = tray.app_handle();
489→                        if let Some(window) = app.get_webview_window("main") {
490→                            let _ = window.show();
491→                            let _ = window.set_focus();
492→                        }
493→                    }
494→                })
495→                .build(app)?;
496→
497→            Ok(())
498→        })
499→        .invoke_handler(tauri::generate_handler![
500→            list_repos,
501→            list_checkpoints,
502→            get_transcript,
503→            get_checkpoint_diff,
504→            get_branch_diff,
505→            list_sessions,
506→            get_entire_settings,
507→            get_entire_logs,
508→            get_raw_checkpoint_metadata,
509→            get_raw_session_file,
510→            spawn_agent,
511→            pty_input,
512→            pty_resize,
513→            kill_pty,
514→            launch_ghostty_agent,
515→            list_trails,
516→            watch_repo,
517→        ])
518→        .run(tauri::generate_context!())
519→        .expect("error while running tauri application");
520→}
