13→/** Hook wrapper to fetch a single session file — must be called at top level */
14→function useSessionFile(repoPath: string, sessionId: string) {
15→  const { data, isLoading } = useRawSessionFileQuery(repoPath, sessionId);
16→  return { sessionId, content: data ?? null, loading: isLoading };
17→}
18→
19→export function CheckpointDebugContainer({
20→  repoPath,
21→  checkpoint,
22→}: CheckpointDebugContainerProps) {
23→  const { data: rawMetadata, isLoading: metadataLoading } = useRawCheckpointMetadataQuery(
24→    repoPath,
25→    checkpoint.checkpoint_id
26→  );
27→
28→  // Fetch raw session files for each session in the checkpoint
29→  // We use individual hooks to satisfy React's rules of hooks (stable call count)
30→  // by always calling for up to 4 session slots
31→  const sessionIds = checkpoint.sessions.map((s) => s.session_id);
32→  const s0 = useSessionFile(repoPath, sessionIds[0] ?? "");
33→  const s1 = useSessionFile(repoPath, sessionIds[1] ?? "");
34→  const s2 = useSessionFile(repoPath, sessionIds[2] ?? "");
35→  const s3 = useSessionFile(repoPath, sessionIds[3] ?? "");
36→
37→  const rawSessionFiles = [s0, s1, s2, s3]
38→    .slice(0, sessionIds.length)
39→    .filter((sf) => sf.sessionId !== "");
40→
41→  return (
42→    <CheckpointDebugView
43→      rawCheckpointMetadata={rawMetadata ?? null}
44→      rawCheckpointMetadataLoading={metadataLoading}
45→      rawSessionFiles={rawSessionFiles}
46→    />
47→  );
48→}
