 49→    let prefix = &checkpoint_id[..2];
 50→    let suffix = &checkpoint_id[2..];
 51→    let session_dir = format!("{}/{}/{}", prefix, suffix, session_index);
 52→
 53→    // Read the checkpoint metadata to find the actual transcript path
 54→    let meta_path = format!("{}/{}/metadata.json", prefix, suffix);
 55→    let transcript_path = read_blob(&repo, &meta_path)
 56→        .ok()
 57→        .and_then(|meta_content| {
 58→            let meta: serde_json::Value = serde_json::from_str(&meta_content).ok()?;
 59→            let sessions = meta.get("sessions")?.as_array()?;
 60→            let session = sessions.get(session_index as usize)?;
 61→            session.get("transcript")?.as_str().map(|s| s.to_string())
 62→        });
 63→
 64→    // Build candidates: metadata path (may be absolute from tree root), then fallbacks
 65→    let mut candidates = Vec::new();
 66→    if let Some(ref path) = transcript_path {
 67→        // Paths from metadata may be absolute (leading /) — strip it for tree lookup
 68→        candidates.push(path.trim_start_matches('/').to_string());
 69→    }
 70→    candidates.push(format!("{}/full.jsonl", session_dir));
 71→    candidates.push(format!("{}/transcript.jsonl", session_dir));
 72→
 73→    for path in &candidates {
 74→        if let Ok(content) = read_blob(&repo, path) {
 75→            return Ok(session::read_transcript(&content));
 76→        }
 77→    }
 78→
 79→    Err(format!("Transcript not found for checkpoint {} session {}", checkpoint_id, session_index))
 80→}
