152→fn build_checkpoint_summary(
153→    repo: &Repository,
154→    _tree: &git2::Tree,
155→    dir: &str,
156→    meta: &RawCheckpointMetadata,
157→) -> Result<CheckpointSummary, String> {
158→    let checkpoint_id = meta
159→        .checkpoint_id
160→        .clone()
161→        .unwrap_or_else(|| dir.replace('/', ""));
162→
163→    let mut sessions = Vec::new();
164→    let mut earliest_created_at: Option<String> = None;
165→    // Read session metadata from subdirectories (0/, 1/, etc.)
166→    if let Some(refs) = &meta.sessions {
167→        for (i, session_ref) in refs.iter().enumerate() {
168→            let session_dir = format!("{}{}/", dir, i);
169→            let session_meta_path = format!("{}metadata.json", session_dir);
170→
171→            // Try to read session metadata from the tree
172→            if let Ok(session_meta) = read_blob_from_tree(repo, &session_meta_path) {
173→                if let Ok(sm) = serde_json::from_str::<RawSessionMetadata>(&session_meta) {
174→                    // Track earliest created_at across sessions
175→                    if let Some(ref ca) = sm.created_at {
176→                        if earliest_created_at.as_ref().map_or(true, |e| ca < e) {
177→                            earliest_created_at = Some(ca.clone());
178→                        }
179→                    }
180→
181→                    // Count steps from transcript if available
182→                    let step_count = count_transcript_steps(repo, session_ref, &session_dir);
183→
184→                    sessions.push(SessionSummary {
185→                        session_id: sm.session_id.unwrap_or_default(),
186→                        agent: sm.agent.unwrap_or_else(|| "Unknown".to_string()),
187→                        model: sm.model,
188→                        step_count,
189→                        summary: sm.summary,
190→                        token_usage: sm.token_usage,
191→                        initial_attribution: sm.initial_attribution,
192→                    });
193→                }
194→            }
195→        }
196→    }
197→
198→    // Use checkpoint metadata fields first, fall back to session-derived values
199→    let created_at = meta
200→        .created_at
201→        .clone()
202→        .or(earliest_created_at)
203→        .unwrap_or_default();
204→
205→    let branch_name = meta.branch.clone().unwrap_or_default();
206→
207→    // Resolve commit_sha and commit_message from the branch's git history
208→    // The checkpoint corresponds to the most recent commit on the branch at created_at time
209→    let (commit_sha, commit_message) = meta
210→        .commit_sha
211→        .clone()
212→        .filter(|s| !s.is_empty())
213→        .map(|sha| {
214→            let msg = meta.commit_message.clone().unwrap_or_default();
215→            (sha, msg)
216→        })
217→        .unwrap_or_else(|| {
218→            resolve_commit_from_branch(repo, &branch_name, &created_at)
219→                .unwrap_or_default()
220→        });
221→
222→    Ok(CheckpointSummary {
223→        checkpoint_id,
224→        branch: branch_name,
225→        commit_sha,
226→        commit_message,
227→        files_touched: meta.files_touched.clone().unwrap_or_default(),
228→        sessions,
229→        token_usage: meta.token_usage.clone(),
230→        created_at,
231→    })
232→}
