234→/// Find the most recent commit on a branch at or before the given timestamp.
235→/// Returns (sha, message) or None if not found.
236→fn resolve_commit_from_branch(
237→    repo: &Repository,
238→    branch_name: &str,
239→    created_at: &str,
240→) -> Option<(String, String)> {
241→    if branch_name.is_empty() || created_at.is_empty() {
242→        return None;
243→    }
244→
245→    let branch = repo.find_branch(branch_name, git2::BranchType::Local).ok()?;
246→    let branch_commit = branch.get().peel_to_commit().ok()?;
247→
248→    // Parse the checkpoint created_at as a unix timestamp for comparison
249→    let checkpoint_ts = parse_iso_timestamp(created_at)?;
250→
251→    // Walk commits from branch HEAD backward
252→    let mut revwalk = repo.revwalk().ok()?;
253→    revwalk.push(branch_commit.id()).ok()?;
254→    revwalk.set_sorting(git2::Sort::TIME).ok()?;
255→
256→    for oid in revwalk {
257→        let oid = oid.ok()?;
258→        let commit = repo.find_commit(oid).ok()?;
259→        let commit_ts = commit.time().seconds();
260→
261→        // Find the first commit whose time is at or before the checkpoint
262→        if commit_ts <= checkpoint_ts {
263→            let sha = oid.to_string();
264→            let message = commit
265→                .summary()
266→                .unwrap_or("")
267→                .to_string();
268→            return Some((sha, message));
269→        }
270→    }
271→
272→    None
273→}
