 88→/// Read transcript from checkpoint data (Claude Code JSONL format)
 89→///
 90→/// Each line is a JSON envelope with a `type` field:
 91→///   - "user"      → message in `.message.content` (string or content blocks)
 92→///   - "assistant"  → message in `.message.content` (array of text/tool_use blocks)
 93→///   - "tool_result"→ tool output in `.content`
 94→///   - "progress", "system", "file-history-snapshot", "last-prompt" → skip
 95→pub fn read_transcript(content: &str) -> Vec<TranscriptMessage> {
 96→    let mut messages = Vec::new();
 97→
 98→    for line in content.lines() {
 99→        if line.trim().is_empty() {
100→            continue;
101→        }
102→        let value: serde_json::Value = match serde_json::from_str(line) {
103→            Ok(v) => v,
104→            Err(_) => continue,
105→        };
106→
107→        let line_type = value.get("type").and_then(|t| t.as_str()).unwrap_or("");
108→        let timestamp = value.get("timestamp").and_then(|t| t.as_str()).map(|s| s.to_string());
109→
110→        match line_type {
111→            "user" => {
112→                let msg = match value.get("message") {
113→                    Some(m) => m,
114→                    None => continue,
115→                };
116→                let text = extract_message_content(msg);
117→                if !text.is_empty() {
118→                    messages.push(TranscriptMessage {
119→                        role: "user".to_string(),
120→                        content: text,
121→                        tool_name: None,
122→                        tool_input: None,
123→                        timestamp,
124→                    });
125→                }
126→            }
127→            "assistant" => {
128→                let msg = match value.get("message") {
129→                    Some(m) => m,
130→                    None => continue,
131→                };
132→                // Assistant content is an array of content blocks
133→                if let Some(blocks) = msg.get("content").and_then(|c| c.as_array()) {
134→                    for block in blocks {
135→                        let block_type = block.get("type").and_then(|t| t.as_str()).unwrap_or("");
136→                        match block_type {
137→                            "text" => {
138→                                let text = block.get("text").and_then(|t| t.as_str()).unwrap_or("");
139→                                if !text.is_empty() {
140→                                    messages.push(TranscriptMessage {
141→                                        role: "assistant".to_string(),
142→                                        content: text.to_string(),
143→                                        tool_name: None,
144→                                        tool_input: None,
145→                                        timestamp: timestamp.clone(),
146→                                    });
147→                                }
148→                            }
149→                            "tool_use" => {
150→                                let name = block.get("name").and_then(|n| n.as_str()).unwrap_or("unknown");
151→                                let input = block.get("input").map(|v| {
152→                                    serde_json::to_string_pretty(v).unwrap_or_default()
153→                                });
154→                                messages.push(TranscriptMessage {
155→                                    role: "assistant".to_string(),
156→                                    content: String::new(),
157→                                    tool_name: Some(name.to_string()),
158→                                    tool_input: input,
159→                                    timestamp: timestamp.clone(),
160→                                });
161→                            }
162→                            _ => {}
163→                        }
164→                    }
165→                }
166→            }
167→            "tool_result" => {
168→                // Tool results can have content at the top level
169→                let text = value
170→                    .get("content")
171→                    .and_then(|c| c.as_str())
172→                    .unwrap_or("")
173→                    .to_string();
174→                let tool_name = value
175→                    .get("tool_name")
176→                    .or_else(|| value.get("name"))
177→                    .and_then(|n| n.as_str())
178→                    .map(|s| s.to_string());
179→                if !text.is_empty() || tool_name.is_some() {
180→                    messages.push(TranscriptMessage {
181→                        role: "tool".to_string(),
182→                        content: text,
183→                        tool_name,
184→                        tool_input: None,
185→                        timestamp,
186→                    });
187→                }
188→            }
189→            _ => {
190→                // Skip progress, system, file-history-snapshot, last-prompt, etc.
191→            }
192→        }
193→    }
194→
195→    messages
196→}
197→
198→/// Extract text content from a message object (handles both string and content blocks)
199→fn extract_message_content(msg: &serde_json::Value) -> String {
200→    if let Some(content) = msg.get("content") {
201→        if let Some(text) = content.as_str() {
202→            return text.to_string();
203→        }
204→        if let Some(arr) = content.as_array() {
205→            let mut parts = Vec::new();
206→            for item in arr {
207→                if let Some(text) = item.get("text").and_then(|t| t.as_str()) {
208→                    parts.push(text.to_string());
209→                }
210→            }
211→            return parts.join("\n");
212→        }
213→    }
214→    String::new()
215→}
